/**
 * @returns The API endpoint for the current stage
 */

export const getAppEndpoint = (): string => {
  if (import.meta.env.PUBLIC_STAGE === 'production') {
    return 'https://us-central1-sequel-tech-production.cloudfunctions.net';
  }
  if (import.meta.env.PUBLIC_STAGE === 'staging') {
    return 'https://us-central1-sequel-tech-staging.cloudfunctions.net';
  }
  // this needs to be 127.0.0.1 in order for the referral code
  // to work in the local dev environment
  return 'http://127.0.0.1:5001/sequel-tech-staging/us-central1';
};

export const getStartupEndpoint = (): string => {
  if (import.meta.env.PUBLIC_STAGE === 'production') {
    return 'https://us-central1-sequel-tech-startups.cloudfunctions.net';
  }
  if (import.meta.env.PUBLIC_STAGE === 'staging') {
    return 'https://us-central1-sequel-tech-startups-staging.cloudfunctions.net';
  }
  return 'http://127.0.0.1:5002/sequel-tech-startups-staging/us-central1';
};
